// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check field 部署コード - enter duplicated code', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check field 部署コード - enter duplicated code', async function() {
    await driver.get("http://localhost:4200/admin-user/add-department");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.xpath("//div[@id=\'department_code\']/div[2]/input")).sendKeys("1111");
    await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-control-input-content")).click();
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "部署コードは重複できません。");
  });
});
